static const char* Caller(DWORD v){
  if(14390==0) return 0;
  int lo=1,hi=14390;
  while(lo<hi){int m=(lo+hi)/2;if(v<F[m].a)hi=m;else lo=m+1;}
  if(lo<=0||lo>14390) return 0;
  if(v-F[lo-1].a>0x10000) return 0;
  return F[lo-1].n;
}

static char sec_none[SEC_BUF_SZ]={0}; static int sec_none_len=0;

static void flush_full(){
  if(h==INVALID_HANDLE_VALUE){
    h=CreateFileA("comparisonResult.log",GENERIC_READ|GENERIC_WRITE,0,0,CREATE_ALWAYS,FILE_ATTRIBUTE_NORMAL,0);
    if(h==INVALID_HANDLE_VALUE) return;
  }
  SetFilePointer(h,0,0,FILE_BEGIN); SetEndOfFile(h);
  std::ostringstream os;
  os<<"============ Different Compares ============\r\n";
  for(int i=0;i<13;i++) if(has_diff[i]&&fn_buf_len[i]>0) os.write(fn_buf[i],fn_buf_len[i]);
  os<<"\r\n================ Captures ================\r\n";
  for(int i=0;i<13;i++) if(is_cap[i]&&!has_diff[i]&&fn_buf_len[i]>0) os.write(fn_buf[i],fn_buf_len[i]);
  os<<"\r\n============= Same Compares ==============\r\n";
  for(int i=0;i<13;i++) if(!is_cap[i]&&!has_diff[i]&&fn_buf_len[i]>0) os.write(fn_buf[i],fn_buf_len[i]);
  os<<"\r\n============== None Calls ================\r\n";
  if(sec_none_len>0) os.write(sec_none,sec_none_len);
  else os<<"\r\n";
  {std::string s=os.str();DWORD n;WriteFile(h,s.c_str(),(DWORD)s.size(),&n,0);}
  FlushFileBuffers(h);
}

static int dirty=0;
static DWORD last_flush_tick=0;
static int total_entries=0;

// Smart flush: diff entries always immediate; first 100 entries immediate;
// after that batch at 32 entries or 1 second timeout
static void maybe_flush(bool is_diff){
  if(is_diff||total_entries<100){{flush_full();dirty=0;last_flush_tick=GetTickCount();return;}}
  DWORD now=GetTickCount();
  if(++dirty>=32||now-last_flush_tick>1000){{flush_full();dirty=0;last_flush_tick=now;}}
}

static void SecApp(char* sec, int* plen, const char* s){
  int sl=lstrlenA(s);
  if(*plen+sl<SEC_BUF_SZ-1){
    for(int i=0;i<sl;i++) sec[(*plen)++]=s[i];
    sec[*plen]=0;
  }
}

