extern "C" DWORD __cdecl LogComparison(DWORD orig,DWORD addr){
  int idx=I(addr);if(idx<0)return orig;
  auto&V=in[idx];

  // Rollback (only if transaction exists; Replace mode has no txn)
  auto*s=shadow::GetSlot();
  if(s&&s->txn) shadow::ShadowTransaction::EndCurrent();

  // Run RE version (RAII guard for re_depth)
  { struct ReDepthGuard { ReDepthGuard() { ++shadow::g_re_depth; } ~ReDepthGuard() { --shadow::g_re_depth; } } g;
    V.re = CallRE(idx);
  }

  // Store RE result in slot for PostProcStub to return to caller
  if(s) { s->re_result_eax = V.re; s->re_result_edx = 0; }  // edx=V.d is INPUT edx, not RE output

  // Compare and log
  DWORD ret=s?s->ret_addr_stack[s->depth]:0;
  write_entry('I', idx, addr, V.re, orig, ret);

  return V.re;
}